<x-inventory.layout title="Dashboard Inventaris"><div class="grid gap-4 md:grid-cols-3"><div class="card card-body"><p>Jenis Barang</p><b class="text-3xl">{{ $totalCategories }}</b></div><div class="card card-body"><p>Data Barang</p><b class="text-3xl">{{ $totalItems }}</b></div><div class="card card-body"><p>Total Jumlah</p><b class="text-3xl">{{ $totalQuantity }}</b></div></div><div class="grid gap-4 lg:grid-cols-2"><section class="card card-body"><h3 class="font-bold">Jumlah per Kondisi</h3>@forelse($byCondition as $row)<p>{{ $row->condition?->name }}: <b>{{ $row->total }}</b></p>@empty<p>Belum ada saldo.</p>@endforelse</section><section class="card card-body"><h3 class="font-bold">Jumlah per Lokasi</h3>@forelse($byLocation as $row)<p>{{ $row->location?->name }}: <b>{{ $row->total }}</b></p>@empty<p>Belum ada saldo.</p>@endforelse</section></div><section class="card card-body"><h3 class="font-bold">Transaksi Terbaru</h3>@foreach($recentTransactions as $tx)<p>{{ $tx->transaction_date->format('d/m/Y') }} · {{ $tx->transaction_number }} · {{ $tx->item?->name }} · {{ $tx->quantity }}</p>@endforeach</section><section class="card card-body"><h3 class="font-bold text-red-700">Peringatan Data Bermasalah</h3>@forelse($alerts as $a)<p>{{ $a->item?->name }} di {{ $a->location?->name }} kondisi {{ $a->condition?->name }} sejumlah {{ $a->quantity }}</p>@empty<p>Tidak ada peringatan inventaris utama.</p>@endforelse</section></x-inventory.layout>
